function getContractInfo(string memory contractName, string memory outDir) internal returns (ContractInfo memory) {
    Vm vm = Vm(CHEATCODE_ADDRESS);

    ContractInfo memory info;

    info.shortName = _toShortName(contractName);

    string memory fileName = _toFileName(contractName);

    // Try direct path first (original behavior)
    string memory artifactPath = string(
        abi.encodePacked(vm.projectRoot(), "/", outDir, "/", fileName, "/", info.shortName, ".json")
    );

    try vm.readFile(artifactPath) returns (string memory artifactJson) {
        return _processArtifact(vm, info, artifactPath, artifactJson);
    } catch {
        artifactPath = _findArtifactByName(vm, outDir, info.shortName);
        string memory artifactJson = vm.readFile(artifactPath);
        return _processArtifact(vm, info, artifactPath, artifactJson);
    }
}

function deploy(
    string memory contractName,
    bytes memory constructorData,
    DefenderOptions memory defenderOpts
) internal returns (address) {
    string memory outDir = Utils.getOutDir();
    ContractInfo memory contractInfo = Utils.getContractInfo(contractName, outDir);
    string memory buildInfoFile = Utils.getBuildInfoFile(
        contractInfo.sourceCodeHash,
        contractInfo.shortName,
        outDir
    );

    string[] memory inputs = buildDeployCommand(contractInfo, buildInfoFile, constructorData, defenderOpts);

    Vm.FfiResult memory result = Utils.runAsBashCommand(inputs);
    string memory stdout = string(result.stdout);

    if (result.exitCode != 0) {
        revert(string(abi.encodePacked("Failed to deploy contract ", contractName, ": ", string(result.stderr))));
    }

    string memory deployedAddress = _parseLine("Deployed to address: ", stdout, true);
    return Vm(Utils.CHEATCODE_ADDRESS).parseAddress(deployedAddress);
}

for (uint256 index = 0; index < configs.length; index++) {
    MarketEmissionConfig storage emissionConfig = configs[index];

    // Go calculate our new values
    IndexUpdate memory supplyUpdate = calculateNewIndex(
        emissionConfig.config.supplyEmissionsPerSec,
        emissionConfig.config.supplyGlobalTimestamp,
        emissionConfig.config.supplyGlobalIndex,
        emissionConfig.config.endTime,
        totalMTokens
    );

    // Set the new values in storage
    emissionConfig.config.supplyGlobalIndex = supplyUpdate.newIndex;
    emissionConfig.config.supplyGlobalTimestamp = supplyUpdate
        .newTimestamp;
    emit GlobalSupplyIndexUpdated(
        _mToken,
        emissionConfig.config.emissionToken,
        supplyUpdate.newIndex,
        supplyUpdate.newTimestamp
    );
}

for (uint256 index = 0; index < configs.length; index++) {
    MarketEmissionConfig storage emissionConfig = configs[index];

    // Go calculate our new borrow index
    IndexUpdate memory borrowIndexUpdate = calculateNewIndex(
        emissionConfig.config.borrowEmissionsPerSec,
        emissionConfig.config.borrowGlobalTimestamp,
        emissionConfig.config.borrowGlobalIndex,
        emissionConfig.config.endTime,
        div_(totalBorrows, marketBorrowIndex)
    );

    // Set the new values in storage
    emissionConfig.config.borrowGlobalIndex = borrowIndexUpdate
        .newIndex;
    emissionConfig.config.borrowGlobalTimestamp = borrowIndexUpdate
        .newTimestamp;

    // Emit an update
    emit GlobalBorrowIndexUpdated(
        _mToken,
        emissionConfig.config.emissionToken,
        emissionConfig.config.borrowGlobalIndex,
        emissionConfig.config.borrowGlobalTimestamp
    );
}

if (vm.contains(stdout, expectedPrefix)) {
    // Get the substring after the prefix
    string[] memory segments = vm.split(stdout, expectedPrefix);
    if (segments.length > 2) {
        revert(
            string(
                abi.encodePacked(
                    "Found multiple occurrences of prefix '",
                    expectedPrefix,
                    "' in output: ",
                    stdout
                )
            )
        );
    }
    string memory suffix = segments[1];
    // Keep only the first line
    return vm.split(suffix, "\n")[0];
} else if (required) {
    revert(
        string(abi.encodePacked("Failed to find line with prefix '", expectedPrefix, "' in output: ", stdout))
    );
} else {
    return "";
}

